import React, { useEffect, useMemo, useRef, useState } from 'react';
import { puzzles } from './data/puzzles.js';
import {
  canonicalBridgeKey,
  canAddBridge,
  computeCurrentCounts,
  isVictory
} from './utils/hashiLogic.js';

const GRID = 40;
const SVG_W = 800;
const SVG_H = 600;

function islandById(islands, id) {
  return islands.find((i) => i.id === id) || null;
}

function bridgeKeyToEndpoints(key) {
  const [x1, y1, x2, y2] = key.split(',').map(Number);
  return { x1, y1, x2, y2 };
}

function findNextIsland(islands, fromId, dir) {
  const from = islandById(islands, fromId);
  if (!from) return fromId;

  let best = null;
  for (const isl of islands) {
    if (isl.id === from.id) continue;

    if (dir === 'left' && isl.y === from.y && isl.x < from.x) {
      const dist = from.x - isl.x;
      if (!best || dist < best.dist) best = { id: isl.id, dist };
    }
    if (dir === 'right' && isl.y === from.y && isl.x > from.x) {
      const dist = isl.x - from.x;
      if (!best || dist < best.dist) best = { id: isl.id, dist };
    }
    if (dir === 'up' && isl.x === from.x && isl.y < from.y) {
      const dist = from.y - isl.y;
      if (!best || dist < best.dist) best = { id: isl.id, dist };
    }
    if (dir === 'down' && isl.x === from.x && isl.y > from.y) {
      const dist = isl.y - from.y;
      if (!best || dist < best.dist) best = { id: isl.id, dist };
    }
  }

  return best ? best.id : fromId;
}

function applyToggleBridge(islands, bridges, from, to) {
  const key = canonicalBridgeKey(from, to);
  const current = bridges.get(key) ?? 0;
  const next = (current + 1) % 3; // 0->1->2->0

  // We'll validate only when increasing (0->1,1->2). For 2->0 always allow.
  if (next === 0) {
    const nextMap = new Map(bridges);
    nextMap.delete(key);
    return { ok: true, bridges: nextMap, error: null };
  }

  const delta = next - current;
  const res = canAddBridge(islands, bridges, from, to, delta);
  if (!res.valid) return { ok: false, bridges, error: res.error };

  const nextMap = new Map(bridges);
  nextMap.set(key, next);
  return { ok: true, bridges: nextMap, error: null };
}

export default function App() {
  const [puzzleIdx, setPuzzleIdx] = useState(0);
  const puzzle = puzzles[puzzleIdx];
  const islands = puzzle.islands;

  const [bridges, setBridges] = useState(() => new Map());
  const [mouseSelectedId, setMouseSelectedId] = useState(null);

  const [cursorId, setCursorId] = useState(islands[0]?.id ?? 0);
  const [kbdSelectedId, setKbdSelectedId] = useState(null);

  const [error, setError] = useState(null);

  const rootRef = useRef(null);

  useEffect(() => {
    // When puzzle changes, fully reset bridges & selection.
    setBridges(new Map());
    setMouseSelectedId(null);
    setKbdSelectedId(null);
    setError(null);
    setCursorId(puzzles[puzzleIdx].islands[0]?.id ?? 0);
  }, [puzzleIdx]);

  const counts = useMemo(() => computeCurrentCounts(islands, bridges), [islands, bridges]);
  const victory = useMemo(() => isVictory(islands, bridges), [islands, bridges]);

  function clearErrorOnValidMove() {
    if (error) setError(null);
  }

  function onIslandClick(isl) {
    if (victory) return;

    if (mouseSelectedId === null) {
      setMouseSelectedId(isl.id);
      return;
    }

    if (mouseSelectedId === isl.id) {
      setMouseSelectedId(null);
      return;
    }

    const from = islandById(islands, mouseSelectedId);
    const to = isl;
    if (!from || !to) {
      setMouseSelectedId(null);
      return;
    }

    const res = applyToggleBridge(islands, bridges, from, to);
    if (!res.ok) {
      setError(res.error);
    } else {
      clearErrorOnValidMove();
      setBridges(res.bridges);
    }

    setMouseSelectedId(null);
  }

  function removeBridgeBetween(from, to) {
    if (victory) return;
    const key = canonicalBridgeKey(from, to);
    if (!(bridges.get(key) > 0)) return;

    const next = new Map(bridges);
    next.delete(key);
    setBridges(next);
    clearErrorOnValidMove();
  }

  function onKeyDown(e) {
    const k = e.key;
    if (k === 'ArrowLeft' || k === 'ArrowRight' || k === 'ArrowUp' || k === 'ArrowDown') {
      e.preventDefault();
      const dir =
        k === 'ArrowLeft'
          ? 'left'
          : k === 'ArrowRight'
            ? 'right'
            : k === 'ArrowUp'
              ? 'up'
              : 'down';
      setCursorId((cur) => findNextIsland(islands, cur, dir));
      return;
    }

    if (k === 'Escape') {
      e.preventDefault();
      setKbdSelectedId(null);
      return;
    }

    if (k === 'Enter') {
      e.preventDefault();
      if (victory) return;

      if (kbdSelectedId === null) {
        setKbdSelectedId(cursorId);
        return;
      }

      if (kbdSelectedId === cursorId) {
        setKbdSelectedId(null);
        return;
      }

      const from = islandById(islands, kbdSelectedId);
      const to = islandById(islands, cursorId);
      const res = applyToggleBridge(islands, bridges, from, to);
      if (!res.ok) {
        setError(res.error);
      } else {
        clearErrorOnValidMove();
        setBridges(res.bridges);
      }
      setKbdSelectedId(null);
    }
  }

  const selectedId = mouseSelectedId ?? kbdSelectedId;

  const bridgeLines = [];
  for (const [key, n] of bridges.entries()) {
    if (!n) continue;
    const { x1, y1, x2, y2 } = bridgeKeyToEndpoints(key);
    const a = { x: x1, y: y1 };
    const b = { x: x2, y: y2 };

    const px1 = a.x * GRID;
    const py1 = a.y * GRID;
    const px2 = b.x * GRID;
    const py2 = b.y * GRID;

    const isHoriz = py1 === py2;
    const offset = 4;

    const mkLine = (dx, dy, idx) => (
      <line
        key={`${key}-${idx}`}
        x1={px1 + dx}
        y1={py1 + dy}
        x2={px2 + dx}
        y2={py2 + dy}
        stroke="#0f0"
        strokeWidth={3}
        shapeRendering="crispEdges"
        onContextMenu={(e) => {
          e.preventDefault();
          const from = islands.find((i) => i.x === x1 && i.y === y1);
          const to = islands.find((i) => i.x === x2 && i.y === y2);
          if (from && to) removeBridgeBetween(from, to);
        }}
        onClick={(e) => {
          if (e.ctrlKey) {
            e.preventDefault();
            const from = islands.find((i) => i.x === x1 && i.y === y1);
            const to = islands.find((i) => i.x === x2 && i.y === y2);
            if (from && to) removeBridgeBetween(from, to);
          }
        }}
      />
    );

    if (n === 1) {
      bridgeLines.push(mkLine(0, 0, 0));
    } else if (n === 2) {
      if (isHoriz) {
        bridgeLines.push(mkLine(0, -offset, 0));
        bridgeLines.push(mkLine(0, +offset, 1));
      } else {
        bridgeLines.push(mkLine(-offset, 0, 0));
        bridgeLines.push(mkLine(+offset, 0, 1));
      }
    }
  }

  const cursorIsland = islandById(islands, cursorId);
  const cursorPx = cursorIsland ? { x: cursorIsland.x * GRID, y: cursorIsland.y * GRID } : { x: 0, y: 0 };

  return (
    <div
      ref={rootRef}
      tabIndex={0}
      onKeyDown={onKeyDown}
      style={{ outline: 'none' }}
    >
      <div style={{ padding: 8 }}>
        <label>
          Puzzle:{' '}
          <select
            value={puzzleIdx}
            onChange={(e) => setPuzzleIdx(Number(e.target.value))}
            style={{ background: 'black', color: '#0f0', border: '1px solid #0f0', fontFamily: 'monospace' }}
          >
            <option value={0}>Easy</option>
            <option value={1}>Medium</option>
            <option value={2}>Hard</option>
          </select>
        </label>{' '}
        <button
          onClick={() => {
            setBridges(new Map());
            setMouseSelectedId(null);
            setKbdSelectedId(null);
            setError(null);
          }}
          style={{ background: 'black', color: '#0f0', border: '1px solid #0f0', fontFamily: 'monospace' }}
        >
          Reset
        </button>
      </div>

      {error ? <div className="error-message" style={{ padding: '0 8px 8px 8px' }}>{error}</div> : null}
      {victory ? <div className="victory-banner" style={{ padding: '0 8px 8px 8px' }}>SOLVED!</div> : null}

      <svg
        width={SVG_W}
        height={SVG_H}
        style={{ position: 'absolute', left: 0, top: 0 }}
        onContextMenu={(e) => e.preventDefault()}
      >
        {/* Bridges first so islands draw on top */}
        {bridgeLines}

        {/* Keyboard cursor (not a circle) */}
        {cursorIsland ? (
          <rect
            x={cursorPx.x - 18}
            y={cursorPx.y - 18}
            width={36}
            height={36}
            fill="none"
            stroke={kbdSelectedId !== null ? '#0f0' : '#0a0'}
            strokeWidth={2}
            strokeDasharray={kbdSelectedId !== null ? '0' : '4 3'}
          />
        ) : null}

        {islands.map((isl) => {
          const cx = isl.x * GRID;
          const cy = isl.y * GRID;
          const isSelected = selectedId === isl.id;
          const cur = counts.get(isl.id) ?? 0;
          const satisfied = cur === isl.value;

          return (
            <g key={isl.id}>
              <circle
                cx={cx}
                cy={cy}
                r={16}
                fill="black"
                stroke={isSelected ? '#9f9' : '#0f0'}
                strokeWidth={2}
                onClick={() => onIslandClick(isl)}
              />
              <text
                x={cx}
                y={cy + 5}
                textAnchor="middle"
                fontFamily="monospace"
                fontSize={16}
                fill={satisfied ? '#9f9' : '#0f0'}
                style={{ userSelect: 'none' }}
                onClick={() => onIslandClick(isl)}
              >
                {isl.value}
              </text>
              <text
                x={cx}
                y={cy + 26}
                textAnchor="middle"
                fontFamily="monospace"
                fontSize={10}
                fill="#0a0"
                style={{ userSelect: 'none' }}
              >
                {cur}/{isl.value}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
}
